import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a permutation?", a: "A permutation is an arrangement where order matters. If you choose 3 winners from 10 people for first, second, and third place, different orders create different outcomes." },
  { q: "What is a combination?", a: "A combination is a selection where order does not matter. If you choose 3 people from 10 for a team, the same people count as one group no matter what order you list them in." },
  { q: "What is the difference between permutation and combination?", a: "Permutations count ordered arrangements, while combinations count unordered selections. Use permutations when position or order matters, and combinations when only the group matters." },
  { q: "How do you calculate factorial?", a: "Factorial means multiplying a positive whole number by every smaller positive whole number. For example, 5! = 5 x 4 x 3 x 2 x 1 = 120. Also, 0! equals 1." },
  { q: "When should you use permutation vs combination?", a: "Use permutation for rankings, passwords, seating orders, and race results. Use combination for committees, lottery picks, teams, and groups where order is irrelevant." },
];

type Mode = "permutation" | "combination";

function factorial(n: number) {
  let value = 1n;
  for (let i = 2n; i <= BigInt(n); i++) value *= i;
  return value;
}

export default function PermutationCombinationCalculator() {
  const [mode, setMode] = useState<Mode>("combination");
  const [n, setN] = useState(10);
  const [r, setR] = useState(3);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    const safeN = Math.floor(n);
    const safeR = Math.floor(r);
    if (safeN < 0 || safeR < 0 || safeR > safeN || safeN > 170) {
      return { label: "Invalid input", value: "Check n and r", formula: "", step: "Use whole numbers where 0 <= r <= n. For performance, keep n at 170 or below." };
    }
    const nFact = factorial(safeN);
    const nrFact = factorial(safeN - safeR);
    if (mode === "permutation") {
      const value = nFact / nrFact;
      return { label: "Permutations nPr", value: value.toLocaleString(), formula: "P(n,r) = n! / (n-r)!", step: `P(${safeN},${safeR}) = ${safeN}! / (${safeN}-${safeR})! = ${nFact.toLocaleString()} / ${nrFact.toLocaleString()} = ${value.toLocaleString()}. Order matters for permutations.` };
    }
    const rFact = factorial(safeR);
    const value = nFact / (rFact * nrFact);
    return { label: "Combinations nCr", value: value.toLocaleString(), formula: "C(n,r) = n! / (r!(n-r)!)", step: `C(${safeN},${safeR}) = ${safeN}! / (${safeR}! x (${safeN}-${safeR})!) = ${nFact.toLocaleString()} / (${rFact.toLocaleString()} x ${nrFact.toLocaleString()}) = ${value.toLocaleString()}. Order does not matter for combinations.` };
  }, [mode, n, r]);

  return (
    <>
      <SEOHead title="Free Permutation and Combination Calculator Online - Calculate nPr and nCr Instantly | CalcHive" description="Free online permutation and combination calculator. Calculate nPr permutations and nCr combinations with full step by step factorial solution instantly. 100% free for students, no signup required." canonical="/permutation-combination-calculator" keywords="free permutation combination calculator, nPr nCr calculator free online, permutation calculator free, combination calculator free, factorial calculator free online" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Permutation and Combination Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free permutation combination calculator to calculate nPr and nCr with complete factorial steps.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="permutation">Permutation nPr</option><option value="combination">Combination nCr</option></select></div>
            <div><label htmlFor="n" className="text-sm font-semibold text-foreground block mb-2">n</label><input id="n" type="number" inputMode="numeric" min="0" value={n} onChange={(event) => setN(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="r" className="text-sm font-semibold text-foreground block mb-2">r</label><input id="r" type="number" inputMode="numeric" min="0" value={r} onChange={(event) => setR(Number(event.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${mode}-${n}-${r}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-5xl font-black text-white tracking-tight break-words" data-testid="result-permutation-combination">{result.value}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Formula and steps</p><p className="text-sm text-foreground font-mono">{result.formula}</p><p className="text-sm text-foreground mt-1" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Permutations and Combinations for Free</h2><p className="text-muted-foreground leading-relaxed">Enter n and r, choose nPr or nCr, and this nPr nCr calculator free online tool applies the factorial formula instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">What is the Difference Between Permutation and Combination</h2><p className="text-muted-foreground leading-relaxed">Permutation calculator free results count ordered arrangements. Combination calculator free results count unordered selections.</p>
          <h2 className="text-2xl font-bold text-foreground">Free nPr and nCr Calculator for Math Students</h2><p className="text-muted-foreground leading-relaxed">Use this factorial calculator free online for probability, counting problems, algebra practice, and statistics homework.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/permutation-combination-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


